    {Pred::ICMP_UGT, 1 << 2}, // 1 only
    {Pred::ICMP_SGT, 1 << 2},
    {Pred::ICMP_EQ,  1 << 1}, // 0 only
    {Pred::ICMP_ULE, (1 << 0) | (1 << 1)}, // -1 or 0
    {Pred::ICMP_SLE, (1 << 0) | (1 << 1)},
    {Pred::ICMP_UGE, (1 << 1) | (1 << 2)}, // 0 or 1
