/// Simplify a switch on the result of llvm.{u,s}cmp intrinsic.
bool SimplifyCFGOpt::simplifyCmpIntrinsicSwitch(SwitchInst *SI,
                                               IRBuilder<> &Builder) {
  Value *Cond = SI->getCondition();
  auto *II = dyn_cast<IntrinsicInst>(Cond);
  if (!II)
    return false;
  Intrinsic::ID ID = II->getIntrinsicID();
  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
    return false;

  Value *LHS = II->getOperand(0);
  Value *RHS = II->getOperand(1);
  Type *CmpTy = LHS->getType();
  assert(CmpTy == RHS->getType());

  // Collect mapping from result value (-1,0,1) to destination block.
  SmallDenseMap<APInt, BasicBlock *, 4> CaseToDest;
  for (auto &Case : SI->cases()) {
    ConstantInt *CI = Case.getCaseValue();
    CaseToDest[CI->getValue()] = Case.getCaseSuccessor();
  }
  BasicBlock *DefaultDest = SI->getDefaultDest();

  // Determine the three possible result values.
  unsigned Width = Cond->getType()->getIntegerBitWidth();
  APInt MinusOne = APInt::getAllOnes(Width);
  APInt Zero = APInt::getZero(Width);
  APInt One = APInt(Width, 1);

  BasicBlock *DestM1 = CaseToDest.lookup(MinusOne);
  BasicBlock *Dest0  = CaseToDest.lookup(Zero);
  BasicBlock *Dest1  = CaseToDest.lookup(One);
  if (!DestM1) DestM1 = DefaultDest;
  if (!Dest0)  Dest0  = DefaultDest;
  if (!Dest1)  Dest1  = DefaultDest;

  // Determine distinct destinations.
  SmallPtrSet<BasicBlock *, 2> Dests;
  Dests.insert(DestM1);
  Dests.insert(Dest0);
  Dests.insert(Dest1);
  if (Dests.size() != 2)
    return false;

  BasicBlock *DestA = *Dests.begin();
  BasicBlock *DestB = *std::next(Dests.begin());

  // Determine which destination is TrueDest (arbitrary).
  // Build mask of result values mapping to DestA.
  unsigned Mask = 0;
  if (DestM1 == DestA) Mask |= 1 << 0;
  if (Dest0 == DestA)  Mask |= 1 << 1;
  if (Dest1 == DestA)  Mask |= 1 << 2;

  // Known masks for predicates.
  // Mapping from predicate to mask: bits for result values where predicate is true.
  // Order: -1, 0, 1.
  using Pred = CmpInst::Predicate;
  const std::pair<Pred, unsigned> PredMasks[] = {
    {Pred::ICMP_ULT, 1 << 0}, // -1 only
    {Pred::ICMP_SLT, 1 << 0},
    {Pred::ICMP_UGT, 1 << 2}, // 1 only
    {Pred::ICMP_SGT, 1 << 2},
    {Pred::ICMP_EQ,  1 << 1}, // 0 only
    {Pred::ICMP_ULE, (1 << 0) | (1 << 1)}, // -1 or 0
    {Pred::ICMP_SLE, (1 << 0) | (1 << 1)},
    {Pred::ICMP_UGE, (1 << 1) | (1 << 2)}, // 0 or 1
    {Pred::ICMP_SGE, (1 << 1) | (1 << 2)},
    {Pred::ICMP_NE,  (1 << 0) | (1 << 2)}, // -1 or 1
  };

  Pred FoundPred = CmpInst::BAD_ICMP_PREDICATE;
  bool Invert = false;
  for (auto &PM : PredMasks) {
    Pred P = PM.first;
    unsigned M = PM.second;
    if (Mask == M) {
      FoundPred = P;
      break;
    }
    // If mask is complement (i.e., DestA is false destination), invert predicate.
    if ((Mask ^ 0b111) == M) {
      FoundPred = P;
      Invert = true;
      break;
    }
  }
  if (FoundPred == CmpInst::BAD_ICMP_PREDICATE)
    return false;

  BasicBlock *TrueDest = DestA;
  BasicBlock *FalseDest = DestB;
  if (Invert)
    std::swap(TrueDest, FalseDest);

  // Now create icmp and branch.
  BasicBlock *BB = SI->getParent();
  Builder.SetInsertPoint(SI);
  Value *Cmp = Builder.CreateICmp(FoundPred, LHS, RHS, "cmp");
  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);

  // Update branch weights if present (copy from turnSwitchRangeIntoICmp).
  if (hasBranchWeightMD(*SI)) {
    SmallVector<uint64_t, 8> Weights;
    getBranchWeights(SI, Weights);
    if (Weights.size() == 1 + SI->getNumCases()) {
      uint64_t TrueWeight = 0;
      uint64_t FalseWeight = 0;
      for (size_t I = 0, E = Weights.size(); I != E; ++I) {
        if (SI->getSuccessor(I) == TrueDest)
          TrueWeight += Weights[I];
        else
          FalseWeight += Weights[I];
      }
      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
        TrueWeight /= 2;
        FalseWeight /= 2;
      }
      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
    }
  }

  // Prune obsolete incoming values off the successors' PHI nodes (copy from turnSwitchRangeIntoICmp).
  for (auto BBI = TrueDest->begin(); isa<PHINode>(BBI); ++BBI) {
    unsigned PreviousEdges = 0;
    for (auto &Case : SI->cases())
      if (Case.getCaseSuccessor() == TrueDest)
        ++PreviousEdges;
    if (SI->getDefaultDest() == TrueDest)
      ++PreviousEdges;
    for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
      cast<PHINode>(BBI)->removeIncomingValue(BB);
  }
  for (auto BBI = FalseDest->begin(); isa<PHINode>(BBI); ++BBI) {
    unsigned PreviousEdges = 0;
    for (auto &Case : SI->cases())
      if (Case.getCaseSuccessor() == FalseDest)
        ++PreviousEdges;
    if (SI->getDefaultDest() == FalseDest)
      ++PreviousEdges;
    for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
      cast<PHINode>(BBI)->removeIncomingValue(BB);
  }

  // Clean up the default block if it's unreachable.
  bool HasDefault =
      !isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg());
  if (!HasDefault) {
    createUnreachableSwitchDefault(SI, this->DTU);
    auto *UnreachableDefault = SI->getDefaultDest();
    SI->eraseFromParent();
    if (this->DTU)
      this->DTU->applyUpdates({{DominatorTree::Delete, BB, UnreachableDefault}});
  } else {
    SI->eraseFromParent();
  }

  return true;
}
